# Check current user
Get-ItemProperty 'HKCU:\Environment' -Name UserInitMprLogonScript -ErrorAction SilentlyContinue
# Check loaded user hives
Get-ChildItem 'HKU:\' -ErrorAction SilentlyContinue | ForEach-Object {
    $val = Get-ItemProperty "HKU:\$($_.PSChildName)\Environment" -Name UserInitMprLogonScript -ErrorAction SilentlyContinue
    if ($val) { Write-Output "User $($_.PSChildName): $($val.UserInitMprLogonScript)" }
}

$paths = @(
    [System.Environment]::GetFolderPath('CommonStartup'),
    [System.Environment]::GetFolderPath('Startup')
)
$shell = New-Object -ComObject WScript.Shell
$paths | ForEach-Object {
    Get-ChildItem $_ -Filter '*.lnk' -ErrorAction SilentlyContinue | ForEach-Object {
        $lnk = $shell.CreateShortcut($_.FullName)
        Write-Output "$($_.Name) -> $($lnk.TargetPath)"
    }
}
